#include <bits/stdc++.h>
using namespace std;

const int N=102;

struct Node{
    int x,y,d;
};

int d[4][2]={{0,-1},{-1,0},{0,1},{1,0}};
int n,a[N][N],dist[N][N][4],sx,sy,ex,ey;
bool init[N][N][4];

void bfs(){
    queue<Node> q;
    q.push({sx,sy,0}),q.push({sx,sy,1}),q.push({sx,sy,2}),q.push({sx,sy,3});
    memset(dist,63,sizeof(dist));
    dist[sx][sy][0]=dist[sx][sy][1]=dist[sx][sy][2]=dist[sx][sy][3]=0;
    init[sx][sy][0]=init[sx][sy][1]=init[sx][sy][2]=init[sx][sy][3]=1;
    while(!q.empty()){
        Node f=q.front();
        q.pop(),init[f.x][f.y][f.d]=0;
        if(dist[f.x][f.y][(f.d+1)%4]>dist[f.x][f.y][f.d]+1){
            dist[f.x][f.y][(f.d+1)%4]=dist[f.x][f.y][f.d]+1;
            if(!init[f.x][f.y][(f.d+1)%4])
                init[f.x][f.y][(f.d+1)%4]=1,q.push({f.x,f.y,(f.d+1)%4});
        }
        if(dist[f.x][f.y][(f.d+3)%4]>dist[f.x][f.y][f.d]+1){
            dist[f.x][f.y][(f.d+3)%4]=dist[f.x][f.y][f.d]+1;
            if(!init[f.x][f.y][(f.d+3)%4])
                init[f.x][f.y][(f.d+3)%4]=1,q.push({f.x,f.y,(f.d+3)%4});
        }
        int xx=f.x+d[f.d][0],yy=f.y+d[f.d][1];
        if(xx>0 && yy>0 && xx<=n && yy<=n  && !a[xx][yy]){
            if(dist[xx][yy][f.d]>dist[f.x][f.y][f.d]){
                dist[xx][yy][f.d]=dist[f.x][f.y][f.d];
                if(!init[xx][yy][f.d])
                    init[xx][yy][f.d]=1,q.push({xx,yy,f.d});
            }
        }
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            char s[2];
            scanf("%s",s);
            a[i][j]=(s[0]=='x');
            if(s[0]=='A')
                sx=i,sy=j;
            if(s[0]=='B')
                ex=i,ey=j;
        }
    bfs();
    int ans=min(min(dist[ex][ey][0],dist[ex][ey][1]),min(dist[ex][ey][2],dist[ex][ey][3]));
    if(ans<1e9)
        printf("%d",ans);
    else
        printf("-1");
    return 0;
}
